        .into_iter()
        .map(|testcase| {
            let before_statements = if let Some(before) = &testcase.input.before {
                Some(
                    before
                        .iter()
                        .map(|id| {
                            testcases_with_ids
                                .get(id)
                                .map(|case| case.sql().clone())
                                .ok_or_else(|| anyhow!("failed to resolve {}: not found", id))
                        })
                        .try_collect()?,
                )
            } else {
                None
            };

            Ok(TestCase {
                input: TestInput {
                    before_statements,
                    ..testcase.input
                },
                ..testcase
            })
        }).try_collect
